    WBBaseActionModel *action = [self buildActionWithNotification:notification];

    NSParameterAssert(action != nil);
    if ([action isKindOfClass:[WBLinkActionModel class]]) {
        WBLinkActionModel *linkAction = (WBLinkActionModel *)action;
        if (linkAction.type == WBLinkActionTypeWBRoute && [linkAction.link containsString:@"/mine/support"]) {
            UITabBarController *rootVC = (UITabBarController *)[WBAppManager getUIApplicationRootViewController];
            NSParameterAssert([rootVC isKindOfClass:[UITabBarController class]]);
            if ([rootVC isKindOfClass:[UITableViewController class]]) {
                UINavigationController *navVC = (UINavigationController  *)rootVC.selectedViewController;
                NSParameterAssert([navVC isKindOfClass:[UINavigationController class]]);
                if ([navVC isKindOfClass:[UINavigationController class]]) {
                    if ([navVC.visibleViewController isKindOfClass:[WBFeedbackViewController class]]) {
                        [linkAction executeWithDefaultHandler:nil];
                        return;
                    }
                }
            }
        }
    }
    completionHandler(UNNotificationPresentationOptionBadge | UNNotificationPresentationOptionSound | UNNotificationPresentationOptionAlert);
}

